"use client";
import { Play, Pause, SkipBack, SkipForward, Volume2 } from 'lucide-react';
import { usePlayerStore } from '@/store/usePlayerStore';

export default function PlayerBar() {
  const { isPlaying, togglePlay, trackDetails, volume, setVolume, currentTime, duration } = usePlayerStore();

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs < 10 ? '0' : ''}${secs}`;
  };

  const progressPercent = duration > 0 ? (currentTime / duration) * 100 : 0;

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-black border-t border-zinc-900 h-24 px-4 flex items-center justify-between z-50">
      <div className="flex items-center gap-4 w-[30%]">
        {trackDetails && (
          <>
            <img src={trackDetails.thumbnail} className="h-14 w-14 object-cover rounded" />
            <div className="flex flex-col overflow-hidden">
              <span className="text-sm font-bold text-white truncate">{trackDetails.title}</span>
              <span className="text-xs text-zinc-400">YouTube Artist</span>
            </div>
          </>
        )}
      </div>

      <div className="flex flex-col items-center gap-2 max-w-[40%] w-full">
        <div className="flex items-center gap-6">
          <SkipBack className="text-zinc-400 hover:text-white cursor-pointer" />
          <button onClick={togglePlay} className="bg-white rounded-full p-2 hover:scale-105 transition">
            {isPlaying ? <Pause className="text-black fill-black" /> : <Play className="text-black fill-black ml-1" />}
          </button>
          <SkipForward className="text-zinc-400 hover:text-white cursor-pointer" />
        </div>
        <div className="w-full flex items-center gap-2 text-xs text-zinc-400">
          <span>{formatTime(currentTime)}</span>
          <div className="flex-1 h-1 bg-zinc-800 rounded-full">
            <div className="h-full bg-white" style={{ width: `${progressPercent}%` }} />
          </div>
          <span>{formatTime(duration)}</span>
        </div>
      </div>

      <div className="w-[30%] flex justify-end items-center gap-3">
        <Volume2 size={20} className="text-zinc-400" />
        <input 
          type="range" min="0" max="1" step="0.01" 
          value={volume} 
          onChange={(e) => setVolume(parseFloat(e.target.value))}
          className="w-24 accent-[#1db954]"
        />
      </div>
    </div>
  );
}