"use client";

import { Home, Search, Library, Plus, ArrowRight, ChevronLeft, ChevronRight } from 'lucide-react';
import Link from 'next/link';
import { useState } from 'react';

export default function Sidebar() {
  const [isExpanded, setIsExpanded] = useState(true);

  return (
    <div className={`h-screen flex flex-col gap-2 p-2 bg-black text-[#b3b3b3] transition-all duration-300 ease-in-out ${isExpanded ? 'w-72' : 'w-20'}`}>
      
      {/* Navigation Section */}
      <nav className="bg-[#121212] rounded-lg p-2 flex flex-col gap-1">
        <div className="flex items-center justify-end px-2 py-1">
           <button 
            onClick={() => setIsExpanded(!isExpanded)}
            className="p-2 hover:bg-[#1f1f1f] rounded-full text-[#b3b3b3] hover:text-white transition-all"
          >
            {isExpanded ? <ChevronLeft size={20} /> : <ChevronRight size={20} />}
          </button>
        </div>
        
        <NavItem href="/" icon={<Home size={24} />} label="Home" isExpanded={isExpanded} active />
        <NavItem href="/search" icon={<Search size={24} />} label="Search" isExpanded={isExpanded} />
      </nav>

      {/* Library Section */}
      <div className="flex-1 bg-[#121212] rounded-lg flex flex-col overflow-hidden">
        <div className="flex items-center justify-between p-4">
          <div className="flex items-center gap-3 hover:text-white cursor-pointer transition-colors">
            <Library size={24} className="shrink-0" />
            {isExpanded && <span className="font-semibold text-sm">Your Library</span>}
          </div>
          
          {isExpanded && (
            <div className="flex items-center gap-1">
              <Plus size={18} className="hover:bg-[#1f1f1f] rounded-full p-1 w-7 h-7 cursor-pointer" />
              <ArrowRight size={18} className="hover:bg-[#1f1f1f] rounded-full p-1 w-7 h-7 cursor-pointer" />
            </div>
          )}
        </div>

        {/* Scrollable Content */}
        <div className="flex-1 overflow-y-auto custom-scrollbar px-2 space-y-2">
          {isExpanded ? (
            <>
              <SidebarCard 
                title="Create your first playlist" 
                description="It's easy, we'll help you" 
                buttonText="Create playlist" 
              />
              <SidebarCard 
                title="Find some podcasts" 
                description="New episodes every day" 
                buttonText="Browse" 
              />
            </>
          ) : (
            <div className="flex flex-col items-center gap-4 py-4">
               {/* Simplified library visual for collapsed state */}
              {[1, 2, 3].map((i) => (
                <div key={i} className="w-12 h-12 bg-[#242424] rounded-md hover:bg-[#2a2a2a] cursor-pointer transition-colors" />
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function NavItem({ href, icon, label, isExpanded, active = false }: any) {
  return (
    <Link 
      href={href} 
      className={`flex items-center gap-4 px-3 py-3 rounded-md transition-all group
        ${active ? 'text-white' : 'hover:bg-[#1a1a1a] hover:text-white'}`}
    >
      <div className="shrink-0 transition-transform group-active:scale-95">{icon}</div>
      {isExpanded && <span className="font-medium text-sm truncate">{label}</span>}
    </Link>
  );
}

function SidebarCard({ title, description, buttonText }: any) {
  return (
    <div className="bg-[#242424] p-4 rounded-lg flex flex-col gap-4 mx-1">
      <div className="space-y-1">
        <h4 className="text-white font-semibold text-sm leading-tight">{title}</h4>
        <p className="text-white text-[12px] opacity-90">{description}</p>
      </div>
      <button className="bg-white text-black text-xs font-bold py-2 px-4 rounded-full w-fit hover:scale-105 active:scale-95 transition-all">
        {buttonText}
      </button>
    </div>
  );
}